<template>
    <div>
        <div class="setting_wrap">
            <div class="radius_list">
                <div class="tit">반지름(m)</div>
                <ul>
                    <li
                        v-for="(data, index) in dataList"
                        :key="index"
                        :class="selectTab === data.RADIUS ? 'active' : ''"
                        @click="changeTab(data, index)"
                    >
                        {{ data.RADIUS }}
                        <button class="btn_x" @click="deleteTab(data.RADIUS)" />
                    </li>
                </ul>

                <div class="add_radius">
                    <input type="number" v-model="addRadius" max="10000" min="50" />
                    <v-btn elevation="3" color="primary" outlined @click="addCircle()"> 추가</v-btn>
                </div>
            </div>
            <div class="radius_setting">
                <p class="tit">{{ selectTab }}m({{ selectTab * 0.001 }}km)</p>
                <div class="setting">
                    <dl>
                        <dt>선</dt>
                        <dd>
                            <div class="line_setting">
                                <v-radio-group hide-details v-model="model.LINE_TYPE">
                                    <v-radio v-for="n in 2" :key="n" :label="n === 1 ? '선 없음' : '선 있음'" :value="n"></v-radio>
                                </v-radio-group>
                                <div class="color_select">
                                    <span class="txt">색</span>
                                    <button @click="doClickLineColor()">
                                        <span
                                            v-for="(color, index) in colorList"
                                            :key="index"
                                            :class="color"
                                            v-show="selectedLineColorIndex === index"
                                        />
                                    </button>
                                    <ul v-if="isLineColorSelected">
                                        <li v-for="(color, index) in colorList" :key="index" :class="color">
                                            <span @click="doSelectLineColor(index)" />
                                        </li>
                                    </ul>
                                </div>
                                <div class="line_width">
                                    <span class="txt">너비</span>
                                    <input type="number" max="10" min="0" v-model="model.LINE_WIDTH" />
                                    <span>pt</span>
                                </div>
                            </div>
                        </dd>
                    </dl>
                    <dl class="fill_wrap">
                        <dt>채우기</dt>
                        <dd>
                            <div class="fill_setting">
                                <v-radio-group hide-details v-model="model.FILL_TYPE">
                                    <v-radio v-for="n in 2" :key="n" :label="n === 1 ? '채우기 없음' : '채우기 있음'" :value="n"></v-radio>
                                </v-radio-group>
                                <div class="color_select">
                                    <span class="txt">색</span>
                                    <button @click="doClickFilleColor()">
                                        <span
                                            v-for="(color, index) in colorList"
                                            :key="index"
                                            :class="color"
                                            v-show="selectedFillColorIndex === index"
                                        />
                                    </button>
                                    <ul v-if="isFillColorSelected">
                                        <li v-for="(color, index) in colorList" :key="index" :class="color">
                                            <span @click="doSelectFillColor(index)" />
                                        </li>
                                    </ul>
                                </div>
                            </div>
                            <div class="fill_opacity">
                                <span class="txt">투명도</span>
                                <div>
                                    <v-slider v-model="model.FILL_TRANSPARENCY" :color="fillOpacity.color" hide-details max="10" min="0"></v-slider>
                                    <input type="number" max="10" min="0" v-model="model.FILL_TRANSPARENCY" />
                                </div>
                            </div>
                        </dd>
                    </dl>
                    <dl class="etc_wrap">
                        <dt>기타</dt>
                        <dd>
                            <div class="input_radius">
                                <span class="txt">이름</span>
                                <input type="text" v-model="model.RADIUS_NAME" />
                            </div>
                            <div class="input_radius">
                                <span class="txt">반지름</span>
                                <input type="number" max="10" min="0" v-model="model.RADIUS" />
                                <span>m</span>
                            </div>
                            <div class="input_check">
                                <v-checkbox v-model="model.DISPLAY_TYPE" label="화면에 표시하기" hide-details />
                                <v-checkbox v-model="model.WARNING_TYPE" label="경고로 경계 지정하기" hide-details />
                            </div>
                            <div class="notice">
                                <span class="btn_notice">?</span>
                                <p class="txt_notice">[설정 > 경고]의 탐지 구역 알람으로 등록합니다.</p>
                            </div>
                        </dd>
                    </dl>
                </div>
            </div>
        </div>
        <div class="btn_area">
            <v-btn elevation="3" color="primary" @click="doSave"> 확인 </v-btn>
        </div>

        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>

<script>
import * as DateUtil from '@/common/DateUtil';
import * as JsonUtil from '@/common/JsonUtil';
import * as LogUtil from '@/common/LogUtil';
import * as MapConfigCircle from '@/rest/MapConfigCircle';

import AlertModal from '@/components/modal/AlertModal';

export default {
    components: {
        AlertModal,
    },
    data: () => ({
        alertModalParams: { isOpened: false, title: '', message: '' },
        dataList: [],

        lineGroup: 1,
        fillGroup: 1,
        selectedLineColorIndex: 0,
        selectedFillColorIndex: 0,
        lineWidth: 0,
        addRadius: null,
        setRadius: 0,
        isLineColorSelected: false,
        isFillColorSelected: false,
        screenOn: false,
        warningOn: false,
        selectTab: '500',
        model: {},
        // colorList: ['#c50202', '#fe6c02', '#fdff00', '#2880fe'],
        // colorList: ['#F44336', '#E91E63', '#9C27B0', '#673AB7', '#3F51B5', '#2196F3', '#03A9F4', '#00BCD4', '#009688', '#4CAF50', '#8BC34A', '#CDDC39', '#FFEB3B', '#FFC107', '#FF9800', '#FF5722', '#795548', '#607D8B', '#9E9E9E', '#000000'],
        colorList: [
            'red',
            'pink',
            'purple',
            'indigo',
            'blue',
            'light-blue',
            'cyan',
            'teal',
            'green',
            'light-green',
            'lime',
            'yellow',
            'amber',
            'orange',
            'brown',
            'blue-grey',
            'grey',
            'black',
        ],
        fillOpacity: { val: 10, color: '#2a85ff' },
        // radiusList: ['500', '1000', '1500', '2000', '2500', '3000', '3500', '4000'],
    }),
    mounted() {
        this.initDataList();
    },
    methods: {
        showAlertModal(msg) {
            this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
        },
        changeTab(data, index) {
            this.selectTab = data.RADIUS;
            this.model = data;
            this.selectedLineColorIndex = this.colorList.indexOf(data.LINE_COLOR);
            this.selectedFillColorIndex = this.colorList.indexOf(data.FILL_COLOR);
            LogUtil.debug('MapCircle: changeTab(): this.selectedLineColorIndex=', this.selectedLineColorIndex);
            LogUtil.debug('MapCircle: changeTab(): this.selectedFillColorIndex=', this.selectedFillColorIndex);
            LogUtil.debug('MapCircle: changeTab(): index=', index);
            this.dataList[index].LINE_COLOR = data.LINE_COLOR;
            this.dataList[index].FILL_COLOR = data.FILL_COLOR;
            LogUtil.debug('MapCircle: changeTab(): this.dataList=', this.dataList);
        },
        deleteTab(radius) {
            const idx = JsonUtil.getObjectIndexByValue(this.dataList, 'RADIUS', radius);
            LogUtil.debug('MapCircle: deleteTab(): idx=', idx);
            this.dataList.splice(idx, 1);
            this.doDeleteOne();
        },
        addCircle() {
            let radiusItems = JsonUtil.getObjectByValue(this.dataList, 'RADIUS', this.addRadius);
            // if (this.addRadius !== null && !this.radiusList.includes(this.addRadius)) {
            //   this.radiusList.push(this.addRadius);
            //   this.addRadius = null;
            //   console.log('this.radiusList', this.radiusList);
            if (this.addRadius === null) {
                this.showAlertModal('반지름 값이 유효하지 않습니다.');
                return;
            }
            if (radiusItems.length < 1) {
                this.dataList.push({
                    MAP_CONFIG_CIRCLE_ID: -1,
                    RADIUS_NAME: '',
                    RADIUS: this.addRadius,
                    LINE_TYPE: 1,
                    LINE_COLOR: 'red',
                    LINE_WIDTH: 2,
                    FILL_TYPE: 1,
                    FILL_COLOR: 'orange',
                    FILL_TRANSPARENCY: 10,
                    DISPLAY_TYPE: 1,
                    WARNING_TYPE: 1,
                });
            } else {
                this.showAlertModal('이미 존재하는 반지름 값입니다.');
            }
        },
        doClickLineColor() {
            this.isLineColorSelected = !this.isLineColorSelected;
        },
        doSelectLineColor(index) {
            this.isLineColorSelected = false;
            this.selectedLineColorIndex = index;
        },
        doClickFilleColor() {
            this.isFillColorSelected = !this.isFillColorSelected;
        },
        doSelectFillColor(index) {
            this.isFillColorSelected = false;
            this.selectedFillColorIndex = index;
        },
        initDataList(condition) {
            let options = {
                conditions: [
                    // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
                ],
                orderBys: [{ name: 'RADIUS', operator: 'asc' }],
                paging: { pageNo: 1, pageSize: 100 },
            };
            if (condition != null) options.conditions.push(condition);

            MapConfigCircle.listByCondition(options)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        this.dataList = res.data.ITEMS;
                        // this.dataList.forEach((item)=>{
                        //   if(item.DETECT_RADIUS != null && item.DEFENSE_RADIUS != null && item.CENTER_RADIUS != null ) {
                        //     item.CIRCLE_INFO = '(' + item.DETECT_RADIUS + ',' + item.DEFENSE_RADIUS + ',' + item.CENTER_RADIUS + ')';
                        //   }
                        // });
                        LogUtil.debug('MapCircle: initDataList(): this.dataList=', this.dataList);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
        doSave() {
            let model = {
                MAP_CONFIG_CIRCLE_ID: this.model.MAP_CONFIG_CIRCLE_ID,
                RADIUS_NAME: this.model.RADIUS_NAME,
                RADIUS: this.model.RADIUS,
                LINE_TYPE: this.model.LINE_TYPE,
                LINE_COLOR: this.colorList[this.selectedLineColorIndex],
                LINE_WIDTH: this.model.LINE_WIDTH,
                FILL_TYPE: this.model.FILL_TYPE,
                FILL_COLOR: this.colorList[this.selectedFillColorIndex],
                FILL_TRANSPARENCY: this.model.FILL_TRANSPARENCY,
                DISPLAY_TYPE: this.model.DISPLAY_TYPE,
                WARNING_TYPE: this.model.WARNING_TYPE,
                CREATED: this.model.CREATED != null ? DateUtil.getTimestamp(this.model.CREATED) : DateUtil.getCurrentTimestamp(),
                UPDATED: DateUtil.getCurrentTimestamp(),
            };

            let selectedIndex = JsonUtil.getObjectIndexByValue(this.dataList, 'RADIUS', this.model.RADIUS);
            this.dataList[selectedIndex].LINE_COLOR = this.colorList[this.selectedLineColorIndex];
            this.dataList[selectedIndex].FILL_COLOR = this.colorList[this.selectedFillColorIndex];
            LogUtil.debug('MapCircle: doSave(): this.model=', this.model);
            MapConfigCircle.save(model)
                .then((res) => {
                    if (res.data.RES_CODE >= 0) {
                        LogUtil.debug('MapCircle: doSave(): res.data.RES_CODE=', res.data);
                        if (this.model.MAP_CONFIG_CIRCLE_ID === -1) {
                            this.model.MAP_CONFIG_CIRCLE_ID = res.data.insertId;
                            LogUtil.debug('MapCircle: doSave(): this.model=', this.model);
                        } else {
                            LogUtil.debug('MapCircle: doSave(): this.model.MAP_CONFIG_CIRCLE_ID=', this.model.MAP_CONFIG_CIRCLE_ID);
                        }
                        this.$emit('popupCloseYes', false);
                    } else {
                        this.showAlertModal(res.data.RES_MSG);
                    }
                })
                .catch((e) => {
                    LogUtil.error('error=', e);
                    this.showAlertModal(e);
                })
                .finally(() => {});
        },
        doDeleteOne() {
            LogUtil.debug('MapCircle: deleteOne(): this.model=', this.model);
            if (this.model.MAP_CONFIG_CIRCLE_ID !== undefined) {
                MapConfigCircle.deleteOne({
                    MAP_CONFIG_CIRCLE_ID: this.model.MAP_CONFIG_CIRCLE_ID,
                })
                    .then((res) => {
                        if (res.data.RES_CODE >= 0) {
                            LogUtil.debug('res.data.RES_CODE=', res.data.RES_CODE);
                            this.initDataList();
                            this.model = {};
                        } else {
                            this.showAlertModal(res.data.RES_MSG);
                        }
                    })
                    .catch((e) => {
                        LogUtil.error('error=', e);
                        this.showAlertModal(e);
                    })
                    .finally(() => {});
            }
        },
    },
};
</script>

<style lang="scss" scoped>
.setting_wrap {
    display: flex;
    width: 1000px;
    height: 680px;
    margin: 0 auto;
    border: 1px solid $color-main03;
    border-radius: 10px;

    input[type='number'] {
        width: 60px;
        height: 38px;
        margin: 0 10px;
        border: 1px solid #ccc;
        border-radius: 8px;
        text-align: center;
    }

    input[type='text'] {
        width: 40px;
        height: 38px;
        margin: 0 10px;
        border: 1px solid #ccc;
        border-radius: 8px;
        text-align: center;
    }

    .radius_list {
        position: relative;
        width: 230px;
        .add_radius {
            @include centerAlign();
            position: absolute;
            bottom: 0;
            width: 100%;
            height: 90px;
            border-top: 1px solid $color-main03;
            input[type='number'] {
                width: 110px;
            }
            button {
                color: #000099 !important;
                caret-color: #000099 !important;
            }
        }
        .tit {
            @include centerAlign();
            height: 60px;
            border-bottom: 1px solid $color-main03;
            font: {
                size: 15px;
            }
        }
        ul {
            overflow-y: auto;
            height: 529px;
            li {
                @include centerAlign();
                position: relative;
                height: 50px;
                border-bottom: 1px solid $color-main03;
                cursor: pointer;
                font: {
                    size: 18px;
                }
                .btn_x {
                    position: absolute;
                    top: 0;
                    right: 0;
                    display: none;
                    width: 42px;
                    height: 100%;
                    background: url('@/assets/setting/ico_x.svg') no-repeat center center;
                    z-index: 2;
                }
                &.active {
                    background-color: $color-main01;
                    color: $color-main04;
                    button {
                        display: block;
                    }
                }
                &.add_radius {
                    position: absolute;
                    bottom: 0;
                    left: 0;
                    width: 100%;
                    height: 90px;
                }
                input[type='number'] {
                    width: 110px;
                }
            }
        }
    }
    .radius_setting {
        width: calc(100% - 230px);
        border-left: 1px solid $color-main03;
        .tit {
            @include centerAlign();
            height: 60px;
            background-color: $color-main01;
            border-radius: 0 10px 0 0;
            font: {
                size: 25px;
            }
            color: $color-main04;
        }
        .setting {
            padding: 18px 40px 0;
            dl {
                & + dl {
                    margin-top: 32px;
                }
                dt {
                    margin: 0 0 13px 13px;
                    font: {
                        size: 18px;
                        weight: 600;
                    }
                }
                dd {
                    padding: 0 15px 15px;
                    border: 1px solid $color-main03;
                    border-radius: 8px;

                    .color_select {
                        @include hCenterAlign();
                        position: relative;
                        .txt {
                            font: {
                                size: 15px;
                                weight: 500;
                            }
                        }
                        button {
                            margin-left: 10px;
                            width: 50px;
                            height: 38px;
                            padding: 8px;
                            background: url('@/assets/setting/fence_color.svg') no-repeat 0 0;
                            span {
                                display: block;
                                width: 20px;
                                height: 20px;
                            }
                        }
                        ul {
                            position: absolute;
                            top: 32px;
                            left: 23px;
                            width: 50px;
                            padding: 6px 0 0;
                            border: 1px solid #ccc;
                            border-top: 0 none;
                            border-radius: 0 0 10px 10px;
                            background: $color-main04;
                            text-align: center;
                            z-index: 2;
                            li {
                                margin-top: 6px;
                                cursor: pointer;
                                span {
                                    display: inline-block;
                                    width: 30px;
                                    height: 30px;
                                }
                            }
                        }
                    }
                    .line_setting {
                        @include centerAlign();
                        .v-input--radio-group--column {
                            width: 30%;
                        }
                        .color_select {
                            width: 30%;
                            margin-top: 15px;
                        }
                        .line_width {
                            margin-top: 15px;
                        }
                    }
                    .fill_setting {
                        @include hCenterAlign();
                        .v-input--radio-group--column {
                            width: 138px;
                            margin-left: 30px;
                        }
                        .color_select {
                            margin-top: 20px;
                        }
                    }
                    .fill_opacity {
                        margin: 15px 7% 0;
                        width: 78%;
                        & > div {
                            display: flex;
                        }
                    }
                }
                &.etc_wrap {
                    dd {
                        display: flex;
                        height: 100px;
                        padding: 0;
                        .input_radius {
                            @include centerAlign();
                            width: 220px;
                            height: inherit;
                            input {
                                width: 80px;
                            }
                        }
                        .input_check {
                            margin-top: 12px;
                            .v-input--checkbox {
                                margin-top: 0;
                                & + .v-input--checkbox {
                                    margin-top: -10px;
                                }
                            }
                        }
                        .notice {
                            position: relative;
                            padding: 56px 0 0 6px;
                            .btn_notice {
                                position: absolute;
                                top: 56px;
                                left: 6px;
                                display: inline-block;
                                width: 20px;
                                height: 20px;
                                background: #c4ddf8;
                                border-radius: 100%;
                                font-size: 15px;
                                text-align: center;
                                color: #2882ff;
                                cursor: pointer;
                                &:hover {
                                    & + p {
                                        display: block;
                                    }
                                }
                            }
                            .txt_notice {
                                position: absolute;
                                top: 52px;
                                left: 34px;
                                display: none;
                                width: 248px;
                                height: 28px;
                                background: #deeeff;
                                border-radius: 8px;
                                font-size: 12px;
                                line-height: 28px;
                                text-align: center;
                                color: #2a85ff;
                            }
                        }
                    }
                }
            }
        }
    }
}
.btn_area {
    @include wCenterAlign();
    width: 800px;
    margin: 30px auto 0;
}
</style>
